import { useState, useEffect } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

const API = "https://team-task-manager-4-7vl7.onrender.com";

export default function Dashboard() {
  const [projects, setProjects] = useState([]);
  const navigate = useNavigate();

  // ✅ SAFE user parse (ONLY ONCE)
  const user = (() => {
    try {
      return JSON.parse(localStorage.getItem("user") || "{}");
    } catch {
      return {};
    }
  })();

  // ✅ SAFE token
  const token = localStorage.getItem("token") || "";

  useEffect(() => {
    fetchProjects();
  }, []);

  const fetchProjects = async () => {
    try {
      console.log("TOKEN SENT:", token);

      const res = await axios.get(`${API}/api/projects`, {
        headers: {
          Authorization: `Bearer ${token}`,
        },
      });

      const data = Array.isArray(res.data)
        ? res.data
        : res.data.projects || [];

      setProjects(data);
    } catch (err) {
      console.error("Error loading projects:", err);
      setProjects([]);
    }
  };

  const logout = () => {
    localStorage.clear();
    navigate("/login");
  };

  return (
    <div style={styles.page}>
      <div style={styles.nav}>
        <h2 style={{ color: "white" }}>📋 Task Manager</h2>

        <div>
          <span style={{ color: "white", marginRight: 10 }}>
            👤 {user?.name || "User"}
          </span>

          <button onClick={logout} style={styles.logoutBtn}>
            Logout
          </button>
        </div>
      </div>

      <div style={styles.content}>
        <h2>Welcome 👋</h2>

        <h3>Your Projects</h3>

        <button style={styles.btn} onClick={() => navigate("/projects")}>
          + New Project
        </button>

        <div style={styles.grid}>
          {projects.map((p) => (
            <div
              key={p._id}
              style={styles.card}
              onClick={() => navigate(`/tasks/${p._id}`)}
            >
              <h3>{p.name}</h3>
              <p>{p.description}</p>
            </div>
          ))}

          {projects.length === 0 && (
            <p style={{ color: "#777" }}>No projects yet</p>
          )}
        </div>
      </div>
    </div>
  );
}

const styles = {
  page: { minHeight: "100vh", background: "#f4f6f7" },
  nav: {
    background: "#0A2342",
    padding: 15,
    display: "flex",
    justifyContent: "space-between",
  },
  content: { padding: 20 },
  grid: {
    display: "grid",
    gridTemplateColumns: "repeat(auto-fill, minmax(250px,1fr))",
    gap: 15,
    marginTop: 15,
  },
  card: {
    background: "white",
    padding: 15,
    borderRadius: 10,
    cursor: "pointer",
  },
  btn: {
    background: "green",
    color: "white",
    padding: 10,
    border: "none",
    borderRadius: 8,
  },
  logoutBtn: {
    background: "transparent",
    color: "white",
    border: "1px solid white",
    padding: 5,
  },
};
